def sanitize_html(fragment: str, allowed_hosts=None) -> str:
    allowed_hosts = allowed_hosts or {"example.pe"}
    safe = html.escape(fragment)
    # política simple: solo links http(s) a hosts allowlisted
    def repl(m):
